import { useState, useEffect, useRef } from "react";

// ── Supabase config ──────────────────────────────────────────────
const SUPABASE_URL = "https://bopslctkjqqgysoukvdv.supabase.co";
const SUPABASE_KEY = "sb_publishable_lAFdhVGoT07CFGEId7bPdg_dHWHOUnm";

async function supabaseGet() {
  const res = await fetch(`${SUPABASE_URL}/rest/v1/recipes?select=*&order=created_at.desc`, {
    headers: { "apikey": SUPABASE_KEY, "Authorization": `Bearer ${SUPABASE_KEY}` }
  });
  return res.json();
}

async function supabasePost(body) {
  const res = await fetch(`${SUPABASE_URL}/rest/v1/recipes`, {
    method: "POST",
    headers: { "apikey": SUPABASE_KEY, "Authorization": `Bearer ${SUPABASE_KEY}`, "Content-Type": "application/json", "Prefer": "return=representation" },
    body: JSON.stringify(body)
  });
  return res.ok;
}

async function supabasePatch(id, body) {
  const res = await fetch(`${SUPABASE_URL}/rest/v1/recipes?id=eq.${id}`, {
    method: "PATCH",
    headers: { "apikey": SUPABASE_KEY, "Authorization": `Bearer ${SUPABASE_KEY}`, "Content-Type": "application/json" },
    body: JSON.stringify(body)
  });
  return res.ok;
}

async function supabaseDelete(id) {
  const res = await fetch(`${SUPABASE_URL}/rest/v1/recipes?id=eq.${id}`, {
    method: "DELETE",
    headers: { "apikey": SUPABASE_KEY, "Authorization": `Bearer ${SUPABASE_KEY}` }
  });
  return res.ok;
}

async function getComments(recipeId) {
  const res = await fetch(`${SUPABASE_URL}/rest/v1/comments?recipe_id=eq.${recipeId}&order=created_at.asc`, {
    headers: { "apikey": SUPABASE_KEY, "Authorization": `Bearer ${SUPABASE_KEY}` }
  });
  return res.json();
}

async function postComment(body) {
  const res = await fetch(`${SUPABASE_URL}/rest/v1/comments`, {
    method: "POST",
    headers: { "apikey": SUPABASE_KEY, "Authorization": `Bearer ${SUPABASE_KEY}`, "Content-Type": "application/json", "Prefer": "return=representation" },
    body: JSON.stringify(body)
  });
  return res.ok;
}

async function deleteComment(id) {
  const res = await fetch(`${SUPABASE_URL}/rest/v1/comments?id=eq.${id}`, {
    method: "DELETE",
    headers: { "apikey": SUPABASE_KEY, "Authorization": `Bearer ${SUPABASE_KEY}` }
  });
  return res.ok;
}

function mapRecipe(r) {
  return {
    id: r.id, title: r.title, author: r.author, category: r.category,
    cuisine: r.cuisine, description: r.description, ingredients: r.ingredients,
    instructions: r.instructions, prepTime: r.prep_time, cookTime: r.cook_time,
    servings: r.servings, photo: r.photo, pin: r.pin, createdAt: r.created_at
  };
}

// ── Exact colors sampled from Tfadalo logo ──────────────────────
const BG        = "#f9f4d4";
const GREEN     = "#3a5437";
const GREEN_MID = "#4d6c43";
const GOLD      = "#e8b84b";
const WHITE     = "#ffffff";
const CARD_BG   = "#fffef5";
const BORDER    = "#e2dba8";
const TEXT_MUTE = "#7a8c6a";

const LOGO = "data:image/png;base64,";


const CATEGORIES = [
  { id: "hot-appetizer",  label: "Hot Appetizers",  emoji: "🔥", color: "#b94040" },
  { id: "cold-appetizer", label: "Cold Appetizers",  emoji: "❄️", color: GREEN },
  { id: "mains-chicken",  label: "Chicken",          emoji: "🍗", color: GREEN_MID },
  { id: "mains-meat",     label: "Meat",             emoji: "🥩", color: "#7a3a2a" },
  { id: "mains-seafood",  label: "Seafood",          emoji: "🦞", color: "#2a6b6b" },
  { id: "dessert",        label: "Desserts",         emoji: "🍮", color: "#b07830" },
];

const CUISINES = [
  { id: "all",            label: "All Cuisines" },
  { id: "levantine",      label: "🫙 Levantine" },
  { id: "gcc",            label: "🌙 GCC" },
  { id: "african",        label: "🌍 African" },
  { id: "european",       label: "🇪🇺 European" },
  { id: "asian",          label: "🥢 Asian" },
  { id: "latin-american", label: "🌶 Latin American" },
  { id: "north-american", label: "🦅 North American" },
];

function getCategoryById(id) {
  return CATEGORIES.find((c) => c.id === id);
}

// ── Comments Section ─────────────────────────────────────────────
function CommentsSection({ recipeId }) {
  const [comments, setComments] = useState([]);
  const [author, setAuthor] = useState("");
  const [content, setContent] = useState("");
  const [posting, setPosting] = useState(false);
  const [loading, setLoading] = useState(true);

  const load = async () => {
    setLoading(true);
    try {
      const data = await getComments(recipeId);
      if (Array.isArray(data)) setComments(data);
    } catch(e) { console.error(e); }
    setLoading(false);
  };

  useEffect(() => { load(); }, [recipeId]);

  const handlePost = async () => {
    if (!author.trim() || !content.trim()) return;
    setPosting(true);
    try {
      await postComment({ recipe_id: recipeId, author: author.trim(), content: content.trim() });
      setContent("");
      await load();
    } catch(e) { console.error(e); }
    setPosting(false);
  };

  const handleDeleteComment = async (id) => {
    if (!window.confirm("Delete this comment?")) return;
    await deleteComment(id);
    await load();
  };

  const inputStyle = {
    width: "100%", padding: "9px 12px",
    border: `1.5px solid ${BORDER}`, borderRadius: 10,
    fontFamily: "\'Alice\', serif", fontSize: 13,
    color: GREEN, background: BG, outline: "none", boxSizing: "border-box"
  };

  return (
    <div style={{ marginTop: 28 }}>
      <h3 style={{ fontFamily: "\'Alice\', serif", fontSize: 18, color: GREEN, margin: "0 0 14px", fontWeight: 400, borderBottom: `2px solid ${GOLD}`, paddingBottom: 6 }}>
        💬 Comments {comments.length > 0 ? `(${comments.length})` : ""}
      </h3>

      {loading ? (
        <div style={{ fontFamily: "\'Alice\', serif", fontSize: 13, color: TEXT_MUTE }}>Loading comments...</div>
      ) : comments.length === 0 ? (
        <div style={{ fontFamily: "\'Alice\', serif", fontSize: 13, color: TEXT_MUTE, marginBottom: 16 }}>No comments yet — be the first!</div>
      ) : (
        <div style={{ display: "flex", flexDirection: "column", gap: 10, marginBottom: 18 }}>
          {comments.map(c => (
            <div key={c.id} style={{ background: BG, border: `1px solid ${BORDER}`, borderRadius: 12, padding: "12px 14px", position: "relative" }}>
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start" }}>
                <div style={{ fontFamily: "\'Alice\', serif", fontSize: 13, color: GREEN_MID, fontWeight: 400, marginBottom: 4 }}>
                  {c.author}
                  <span style={{ color: TEXT_MUTE, fontSize: 11, marginLeft: 8 }}>
                    {new Date(c.created_at).toLocaleDateString("en-GB", { day: "numeric", month: "short" })}
                  </span>
                </div>
                <button
                  onClick={() => handleDeleteComment(c.id)}
                  style={{ background: "none", border: "none", cursor: "pointer", color: TEXT_MUTE, fontSize: 13, padding: "0 2px", lineHeight: 1 }}
                  title="Delete comment"
                >×</button>
              </div>
              <div style={{ fontFamily: "\'Alice\', serif", fontSize: 14, color: GREEN, lineHeight: 1.55 }}>{c.content}</div>
            </div>
          ))}
        </div>
      )}

      {/* Add comment */}
      <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
        <input
          style={inputStyle}
          placeholder="Your name"
          value={author}
          onChange={e => setAuthor(e.target.value)}
        />
        <textarea
          style={{ ...inputStyle, resize: "vertical", minHeight: 70 }}
          placeholder="Leave a comment..."
          value={content}
          onChange={e => setContent(e.target.value)}
        />
        <button
          onClick={handlePost}
          disabled={posting || !author.trim() || !content.trim()}
          style={{
            alignSelf: "flex-end", background: GREEN, color: WHITE,
            border: "none", borderRadius: 10, padding: "9px 20px",
            fontFamily: "\'Alice\', serif", fontSize: 13, cursor: "pointer",
            opacity: posting || !author.trim() || !content.trim() ? 0.6 : 1,
            transition: "opacity 0.15s"
          }}
        >{posting ? "Posting..." : "Post Comment"}</button>
      </div>
    </div>
  );
}

